// Evaluate multi-hazard thresholds from weather data
const hourly = $input.first().json.hourly || {};
const times = hourly.time || [];
const alerts = [];

for (let i = 0; i < Math.min(times.length, 72); i++) {
  const temp = hourly.temperature_2m?.[i] || 0;
  const wind = hourly.wind_speed_10m?.[i] || 0;
  const gusts = hourly.wind_gusts_10m?.[i] || 0;
  const precip = hourly.precipitation?.[i] || 0;
  const humidity = hourly.relative_humidity_2m?.[i] || 0;
  const soil = hourly.soil_moisture_0_to_1cm?.[i] || 0;

  // SEVERE STORM: gusts > 60 km/h
  if (gusts > 60) alerts.push({ type: 'severe_storm', severity: gusts > 80 ? 'critical' : 'high', time: times[i], detail: `Gusts ${gusts} km/h, wind ${wind} km/h` });

  // HEATWAVE: temp > 30°C
  if (temp > 30) alerts.push({ type: 'heatwave', severity: temp > 35 ? 'critical' : 'high', time: times[i], detail: `Temperature ${temp}°C, humidity ${humidity}%` });

  // FLOOD RISK: heavy rain > 10mm/h
  if (precip > 10) alerts.push({ type: 'flood', severity: precip > 25 ? 'critical' : precip > 15 ? 'high' : 'medium', time: times[i], detail: `Precipitation ${precip} mm/h` });

  // LANDSLIDE RISK: high soil moisture + rain
  if (soil > 0.4 && precip > 5) alerts.push({ type: 'landslide', severity: soil > 0.6 ? 'high' : 'medium', time: times[i], detail: `Soil moisture ${(soil*100).toFixed(0)}%, rain ${precip}mm` });
}

return [{ json: { alerts, evaluatedAt: new Date().toISOString(), totalAlerts: alerts.length } }];
